"""A readable parser for standard 5-field cron expressions.

The module is organized so it reads top-to-bottom:

    1. Errors and field definitions   -- the vocabulary
    2. Data structures                -- FieldPart, CronField, CronSchedule
    3. Field-level parsing            -- parse_field and its small helpers
    4. Expression parsing             -- parse_cron (the public entry point)
    5. Description rendering          -- turning a schedule into English

Cron format:  "minute hour day_of_month month day_of_week"
"""

from __future__ import annotations

from dataclasses import dataclass
from typing import Callable

# --------------------------------------------------------------------------- #
# 1. Errors and field definitions
# --------------------------------------------------------------------------- #


class CronParseError(ValueError):
    """Raised when an expression is malformed or out of range."""


@dataclass(frozen=True)
class FieldDefinition:
    """The name and inclusive value bounds of a single cron field."""

    name: str
    min_value: int
    max_value: int


MINUTE = FieldDefinition("minute", 0, 59)
HOUR = FieldDefinition("hour", 0, 23)
DAY_OF_MONTH = FieldDefinition("day of month", 1, 31)
MONTH = FieldDefinition("month", 1, 12)
DAY_OF_WEEK = FieldDefinition("day of week", 0, 6)

# The five fields, in the order they appear in an expression.
FIELD_ORDER: tuple[FieldDefinition, ...] = (
    MINUTE,
    HOUR,
    DAY_OF_MONTH,
    MONTH,
    DAY_OF_WEEK,
)

WEEKDAY_NAMES = (
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
)
MONTH_NAMES = (
    "",  # padding so MONTH_NAMES[1] == "January"
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
)


# --------------------------------------------------------------------------- #
# 2. Data structures
# --------------------------------------------------------------------------- #


@dataclass(frozen=True)
class FieldPart:
    """One comma-separated component of a field, normalized to start/stop/step.

    Every cron component -- a wildcard, a range, a single value, or a step --
    can be expressed as "walk from `start` to `stop` in `step` increments".
    Keeping that single shape is what lets one function parse all five fields.
    """

    start: int
    stop: int
    step: int
    from_wildcard: bool  # True when the component was written as "*" or "*/n"

    @property
    def values(self) -> list[int]:
        return list(range(self.start, self.stop + 1, self.step))


@dataclass(frozen=True)
class CronField:
    """A fully parsed field: its definition plus its comma-separated parts."""

    definition: FieldDefinition
    parts: tuple[FieldPart, ...]

    @property
    def values(self) -> list[int]:
        """The sorted, de-duplicated set of values this field matches."""
        matched: set[int] = set()
        for part in self.parts:
            matched.update(part.values)
        return sorted(matched)

    # -- shape predicates, used only for rendering descriptions -------------- #

    @property
    def is_wildcard(self) -> bool:
        """True for a plain "*" (matches every value)."""
        return self._is_single_part and self._only.from_wildcard and self.step == 1

    @property
    def is_stepped_wildcard(self) -> bool:
        """True for "*/n" (every nth value)."""
        return self._is_single_part and self._only.from_wildcard and self.step > 1

    @property
    def is_single(self) -> bool:
        """True for an exact single value such as "42"."""
        return self._is_single_part and self._only.start == self._only.stop

    @property
    def is_range(self) -> bool:
        """True for a contiguous range such as "1-5"."""
        return (
            self._is_single_part
            and not self._only.from_wildcard
            and self._only.step == 1
            and self._only.start < self._only.stop
        )

    @property
    def step(self) -> int:
        return self._only.step

    @property
    def _is_single_part(self) -> bool:
        return len(self.parts) == 1

    @property
    def _only(self) -> FieldPart:
        return self.parts[0]


@dataclass(frozen=True)
class CronSchedule:
    """The parsed result of an entire cron expression."""

    expression: str
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Return a human-readable English description of the schedule."""
        when = describe_time(self.minute, self.hour)
        on = describe_calendar(self.day_of_month, self.month, self.day_of_week)
        return f"{when} {on}" if on else when


# --------------------------------------------------------------------------- #
# 3. Field-level parsing (shared by all five fields)
# --------------------------------------------------------------------------- #


def parse_field(text: str, definition: FieldDefinition) -> CronField:
    """Parse one field (e.g. "1-30/5,45") into a CronField."""
    parts = tuple(parse_part(item, definition) for item in text.split(","))
    return CronField(definition, parts)


def parse_part(item: str, definition: FieldDefinition) -> FieldPart:
    """Parse a single comma-separated component into a normalized FieldPart."""
    base, step = split_step(item, definition)
    start, stop, from_wildcard = parse_base_range(base, definition)
    return FieldPart(start, stop, step, from_wildcard)


def split_step(item: str, definition: FieldDefinition) -> tuple[str, int]:
    """Split "base/step" into its base and step; default step is 1."""
    if "/" not in item:
        return item, 1
    base, _, step_text = item.partition("/")
    step = parse_int(step_text, definition, "step")
    if step < 1:
        raise CronParseError(f"step must be >= 1 in {definition.name} field: '{item}'")
    return base, step


def parse_base_range(
    base: str, definition: FieldDefinition
) -> tuple[int, int, bool]:
    """Resolve the base ("*", "a-b", or "a") into (start, stop, from_wildcard)."""
    if base == "*":
        return definition.min_value, definition.max_value, True
    if "-" in base:
        start_text, _, stop_text = base.partition("-")
        start = parse_value(start_text, definition)
        stop = parse_value(stop_text, definition)
        if start > stop:
            raise CronParseError(
                f"range start {start} is after stop {stop} in {definition.name} field"
            )
        return start, stop, False
    value = parse_value(base, definition)
    return value, value, False


def parse_value(text: str, definition: FieldDefinition) -> int:
    """Parse a single integer and verify it falls within the field's bounds."""
    value = parse_int(text, definition, "value")
    if not definition.min_value <= value <= definition.max_value:
        raise CronParseError(
            f"{definition.name} value {value} is out of range "
            f"{definition.min_value}-{definition.max_value}"
        )
    return value


def parse_int(text: str, definition: FieldDefinition, label: str) -> int:
    """Parse an integer, raising a clear error if it is not numeric."""
    try:
        return int(text)
    except ValueError:
        raise CronParseError(
            f"invalid {label} '{text}' in {definition.name} field"
        ) from None


# --------------------------------------------------------------------------- #
# 4. Expression parsing (public entry point)
# --------------------------------------------------------------------------- #


def parse_cron(expression: str) -> CronSchedule:
    """Parse a standard 5-field cron expression into a CronSchedule."""
    tokens = expression.split()
    if len(tokens) != 5:
        raise CronParseError(
            f"expected 5 fields, got {len(tokens)}: '{expression.strip()}'"
        )
    fields = [parse_field(token, defn) for defn, token in zip(FIELD_ORDER, tokens)]
    return CronSchedule(expression.strip(), *fields)


# --------------------------------------------------------------------------- #
# 5. Description rendering
# --------------------------------------------------------------------------- #


def describe_time(minute: CronField, hour: CronField) -> str:
    """Describe the time-of-day clause from the minute and hour fields."""
    if minute.is_wildcard and hour.is_wildcard:
        return "Every minute"
    if minute.is_stepped_wildcard and hour.is_wildcard:
        return f"Every {minute.step} minutes"
    if is_exactly(minute, 0) and hour.is_stepped_wildcard:
        return f"Every {hour.step} hours, on the hour"
    if minute.is_single and hour.is_single:
        return describe_clock_time(hour.values[0], minute.values[0])
    return describe_generic_time(minute, hour)


def describe_clock_time(hour_value: int, minute_value: int) -> str:
    """Render an exact wall-clock time such as "At 08:30"."""
    if hour_value == 0 and minute_value == 0:
        return "At midnight"
    return f"At {hour_value:02d}:{minute_value:02d}"


def describe_generic_time(minute: CronField, hour: CronField) -> str:
    """Fallback phrasing for minute/hour combinations without a special case."""
    minute_phrase = describe_field(minute, str)
    hour_phrase = describe_field(hour, str)
    return f"At minute {minute_phrase} past hour {hour_phrase}"


def describe_calendar(
    day_of_month: CronField, month: CronField, day_of_week: CronField
) -> str:
    """Describe the date clause from the day-of-week, day-of-month, and month."""
    clauses = [
        describe_weekday(day_of_week),
        describe_month_day(day_of_month, month),
    ]
    return " ".join(clause for clause in clauses if clause)


def describe_weekday(day_of_week: CronField) -> str:
    """Describe the day-of-week field, e.g. "on Monday through Friday"."""
    if day_of_week.is_wildcard:
        return ""
    return "on " + describe_field(day_of_week, lambda value: WEEKDAY_NAMES[value])


def describe_month_day(day_of_month: CronField, month: CronField) -> str:
    """Describe the day-of-month and month together, e.g. "on the 1st of March"."""
    day_specified = not day_of_month.is_wildcard
    month_specified = not month.is_wildcard
    if not day_specified and not month_specified:
        return ""
    if day_specified:
        day_phrase = "on the " + describe_field(day_of_month, ordinal)
        month_phrase = (
            "of " + describe_field(month, lambda value: MONTH_NAMES[value])
            if month_specified
            else "of every month"
        )
        return f"{day_phrase} {month_phrase}"
    return "in " + describe_field(month, lambda value: MONTH_NAMES[value])


def describe_field(field: CronField, name_of: Callable[[int], str]) -> str:
    """Render a field's selected values using `name_of` to label each number.

    Handles the four readable shapes: wildcard, step, range, and explicit list.
    """
    if field.is_wildcard:
        return "every value"
    if field.is_stepped_wildcard:
        return f"every {ordinal(field.step)}"
    if field.is_range:
        return f"{name_of(field.values[0])} through {name_of(field.values[-1])}"
    return join_with_and([name_of(value) for value in field.values])


# -- small text helpers ----------------------------------------------------- #


def is_exactly(field: CronField, value: int) -> bool:
    """True when a field matches exactly one value equal to `value`."""
    return field.is_single and field.values[0] == value


def join_with_and(items: list[str]) -> str:
    """Join items into a natural English list ("a", "a and b", "a, b, and c")."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


def ordinal(number: int) -> str:
    """Convert an integer into its ordinal form ("1st", "2nd", "13th")."""
    if 10 <= number % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(number % 10, "th")
    return f"{number}{suffix}"


# --------------------------------------------------------------------------- #
# Demo
# --------------------------------------------------------------------------- #

if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expr in examples:
        print(f"{expr:>15}  ->  {parse_cron(expr).describe()}")
